iOS有时候会用到的小技巧记录文档


获取某个view所在的控制器
12345678910111213- (UIViewController *)viewController&#123;  UIViewController *viewController = nil;    UIResponder *next = self.nextResponder;  while (next) &#123;    if ([nextisKindOfClass:[UIViewController class]]) &#123;      viewController = (UIViewController *)next;            break;        &#125;        next = next.nextResponder;    &#125;     return viewController;&#125;
iOS跳转到App Store下载应用评分
1[[UIApplication sharedApplication] openURL:[NSURL URLWithString:@&quot;itms-apps://itunes.apple.com/WebObjects/MZStore.woa/wa/viewContentsUserReviews?type=Purple+Software&amp;id=APPID&quot;]];

iOS 获取汉字的拼音
123456789101112+ (NSString *)transform:(NSString *)chinese &#123;        //将NSString装换成NSMutableString    NSMutableString *pinyin = [chinese mutableCopy];        //将汉字转换为拼音(带音标)        CFStringTransform((__bridgeCFMutableStringRef)pinyin, NULL, kCFStringTransformMandarinLatin, NO);        NSLog(@&quot;%@&quot;, pinyin);        //去掉拼音的音标        CFStringTransform((__bridgeCFMutableStringRef)pinyin, NULL, kCFStringTransformStripCombiningMarks, NO);        NSLog(@&quot;%@&quot;, pinyin);        //返回最近结果        return pinyin; &#125;
判断view是不是指定视图的子视图
1BOOL isView = [textView isDescendantOfView:self.view];
修改UITextField中Placeholder的文字颜色和大小
123[self.textFieldsetValue:[UIColorredColor] forKeyPath:@&quot;_placeholderLabel.textColor&quot;];[self.textFieldsetValue:[UIFontboldSystemFontOfSize:16] forKeyPath:@&quot;_placeholderLabel.font&quot;];
NSDateFormatter的格式
123456789101112131415161718G: 公元时代，例如AD公元yy: 年的后2位yyyy: 完整年MM: 月，显示为1-12MMM: 月，显示为英文月份简写,如 JanMMMM: 月，显示为英文月份全称，如 Janualydd: 日，2位数表示，如02d: 日，1-2位显示，如 2EEE: 简写星期几，如SunEEEE: 全写星期几，如Sundayaa: 上下午，AM/PMH: 时，24小时制，0-23K：时，12小时制，0-11m: 分，1-2位mm: 分，2位s: 秒，1-2位ss: 秒，2位S: 毫秒
验证移动手机号：
123456+ (BOOL)isMobile:(NSString*)mobile&#123;    NSString *regex = @&quot;^1+[34578]+\d&#123;9&#125;&quot;;    NSPredicate *pred = [NSPredicate predicateWithFormat:@&quot;SELF MATCHES %@&quot;, regex];    return [pred evaluateWithObject:mobile];&#125;
邮箱验证：
123456+ (BOOL)isEmail:(NSString*)email&#123;    NSString *regex = @&quot;^[\\w-]+(\\.[\\w-]+)*@[\\w-]+(\\.[\\w-]+)+$&quot;;    NSPredicate *pred = [NSPredicate predicateWithFormat:@&quot;SELF MATCHES %@&quot;, regex];    return [pred evaluateWithObject:email];&#125;
整形验证
12345+ (BOOL)isPureInt:(NSString*)string&#123;    NSScanner* scan = [NSScanner scannerWithString:string];    int val;    return[scan scanInt:&amp;val] &amp;&amp; [scan isAtEnd];&#125;
浮点型验证
12345- (BOOL)isPureFloat:(NSString*)string&#123;    NSScanner* scan = [NSScanner scannerWithString:string];    float val;    return[scan scanFloat:&amp;val] &amp;&amp; [scan isAtEnd];&#125;
中文验证
123456+ (BOOL)isChinese:(NSString*)chinese&#123;    NSString *regex = @&quot;^[\u4e00-\u9fa5]&quot;;    NSPredicate *pred = [NSPredicate predicateWithFormat:@&quot;SELF MATCHES %@&quot;, regex];    return [pred evaluateWithObject: chinese];&#125;
网址URL验证
123456+ (BOOL)isURL:(NSString*)url&#123;    NSString *regex = @&quot;[a-zA-z]+://[^\s]*&quot;;    NSPredicate *pred = [NSPredicate predicateWithFormat:@&quot;SELF MATCHES %@&quot;, regex];    return [pred evaluateWithObject: url];&#125;
身份证号验证
12345678910111213141516171819202122232425262728293031323334353637+ (BOOL)verifyIDCardNumber:(NSString *)IDCardNumber &#123; IDCardNumber = [IDCardNumber stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]]; if ([IDCardNumber length] != 18) &#123; return NO; &#125; NSString *mmdd = @”(((0[13578]|1[02])(0[1-9]|[12][0-9]|3[01]))|((0[469]|11)(0[1-9]|[12][0-9]|30))|(02(0[1-9]|[1][0-9]|2[0-8])))”; NSString *leapMmdd = @”0229”; NSString *year = @”(19|20)[0-9]&#123;2&#125;”; NSString *leapYear = @”(19|20)(0[48]|[2468][048]|[13579][26])”; NSString *yearMmdd = [NSString stringWithFormat:@”%@%@”, year, mmdd]; NSString *leapyearMmdd = [NSString stringWithFormat:@”%@%@”, leapYear, leapMmdd]; NSString *yyyyMmdd = [NSString stringWithFormat:@”((%@)|(%@)|(%@))”, yearMmdd, leapyearMmdd, @”20000229”]; NSString *area = @”(1[1-5]|2[1-3]|3[1-7]|4[1-6]|5[0-4]|6[1-5]|82|[7-9]1)[0-9]&#123;4&#125;”; NSString *regex = [NSString stringWithFormat:@”%@%@%@”, area, yyyyMmdd , @”[0-9]&#123;3&#125;[0-9Xx]”];NSPredicate *regexTest = [NSPredicate predicateWithFormat:@&quot;SELF MATCHES %@&quot;, regex];if (![regexTest evaluateWithObject:IDCardNumber])&#123;    return NO;&#125;int summary = ([IDCardNumber substringWithRange:NSMakeRange(0,1)].intValue + [IDCardNumber substringWithRange:NSMakeRange(10,1)].intValue) *7+ ([IDCardNumber substringWithRange:NSMakeRange(1,1)].intValue + [IDCardNumber substringWithRange:NSMakeRange(11,1)].intValue) *9+ ([IDCardNumber substringWithRange:NSMakeRange(2,1)].intValue + [IDCardNumber substringWithRange:NSMakeRange(12,1)].intValue) *10+ ([IDCardNumber substringWithRange:NSMakeRange(3,1)].intValue + [IDCardNumber substringWithRange:NSMakeRange(13,1)].intValue) *5+ ([IDCardNumber substringWithRange:NSMakeRange(4,1)].intValue + [IDCardNumber substringWithRange:NSMakeRange(14,1)].intValue) *8+ ([IDCardNumber substringWithRange:NSMakeRange(5,1)].intValue + [IDCardNumber substringWithRange:NSMakeRange(15,1)].intValue) *4+ ([IDCardNumber substringWithRange:NSMakeRange(6,1)].intValue + [IDCardNumber substringWithRange:NSMakeRange(16,1)].intValue) *2+ [IDCardNumber substringWithRange:NSMakeRange(7,1)].intValue *1 + [IDCardNumber substringWithRange:NSMakeRange(8,1)].intValue *6+ [IDCardNumber substringWithRange:NSMakeRange(9,1)].intValue *3;NSInteger remainder = summary % 11;NSString *checkBit = @&quot;&quot;;NSString *checkString = @&quot;10X98765432&quot;;checkBit = [checkString substringWithRange:NSMakeRange(remainder,1)];// 判断校验位return [checkBit isEqualToString:[[IDCardNumber substringWithRange:NSMakeRange(17,1)] uppercaseString]];&#125;
